howItWorks.step1Code:
yourCenturion.understand({
  mission: 'yours',
  privacy: 'absolute',
  home: 'defined',
  leavesHome: false
})

// Begrepen – en het blijft bij je.

howItWorks.step2Code:
yourCenturion.place({
  where: 'your home',
  outsideWorld: 'your choice',
  leaves: false
})

// Gevestigd. Niets dwaalt af.

howItWorks.step3Code:
yourCenturion.live({
  always: true,
  learns: 'from you only',
  shares: 'nothing',
  companySees: 'nothing'
})

// Privé. Loyaal. De jouwe.

developers.code1:
// Skills van anderen worden niet vertrouwd
skill.fromSomeoneElse({
  trust: 'none',
  risk: 'stolen secrets | hidden behaviour'
})

// Centurion installeert niet
// alleen op uw woord de skill van een vreemde.

developers.code2:
centurion.makeSkill({
  for: 'what you actually need',
  basedOn: 'your life's mission',
  author: 'your Centurion'
})

// Het bouwt skills. Het gaat niet
// in een winkel naar skills zoeken.

developers.code3:
work.continues({
  gap: 'found',
  skill: 'made now',
  stays: 'with you'
})

// Skills verschijnen wanneer ze nodig zijn —
// en blijven bij u thuis, onder uw controle.

developers.code4:
loop.run({
  notice: true,
  act: true,
  learn: true,
  improve: true
})

// Merk op. Handel. Leer. Verbeter.
// Skills worden beter door gebruik —
// zonder naar huis te rapporteren.

